import anthropic
import json

client = anthropic.Anthropic()

def detect_no_action_stuck(resp) -> str | None:
    """
    Check if the model stopped without making a tool call.
    Returns a description if stuck, else None.
    """
    tool_calls = [b for b in resp.content if b.type == "tool_use"]
    text_blocks = [b for b in resp.content if b.type == "text"]

    if tool_calls:
        return None  # Model made tool calls — not stuck

    if resp.stop_reason == "end_turn":
        # Model generated text and stopped — it thinks it is done
        text = " ".join(b.text for b in text_blocks).strip()
        return f"no_action: model output text without tool call (stop_reason=end_turn): {text[:80]}..."

    if resp.stop_reason == "max_tokens":
        return "truncated: model output was cut off (max_tokens too small)"

    return None

REQUIRE_TOOL_SYSTEM = """
You are a research assistant. You MUST use the provided tools to answer questions.
Never answer from memory alone. Always call task_complete with your answer.
"""

def run_with_no_action_recovery(user_message: str, tools: list, dispatch: dict) -> dict:
    messages = [{"role": "user", "content": user_message}]
    no_action_count = 0
    max_no_action = 2

    for _ in range(12):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=REQUIRE_TOOL_SYSTEM,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "result": block.input}

        stuck = detect_no_action_stuck(resp)
        if stuck:
            no_action_count += 1
            if no_action_count >= max_no_action:
                return {"status": "stuck", "detail": stuck}
            # Recovery: remind the agent to use the tool
            messages.append({"role": "user", "content":
                "You did not use a tool. You must call task_complete with your answer. "
                "Call task_complete now."})
            continue

        if not tool_calls:
            return {"status": "stuck"}

        results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations"}

import anthropic
import json

client = anthropic.Anthropic()

REPLAN_INJECTION = (
    "You appear to be repeating the same action. "
    "This approach is not working. "
    "Change your strategy: try a different query, a different tool, or a different approach. "
    "If no alternative exists, call task_failed with a clear explanation."
)

def run_agent_with_loop_detection(system, tools, dispatch, user_message, max_iterations=15):
    guard = LoopGuard(exact_repeat_threshold=3, cycle_length=2)
    messages = [{"role": "user", "content": user_message}]
    injections_used = 0
    max_injections = 2

    for iteration in range(1, max_iterations + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "result": block.input}
            if block.name == "task_failed":
                return {"status": "failed", "reason": block.input.get("reason", "")}

        # No-action check
        no_action = detect_no_action_stuck(resp)
        if no_action and not tool_calls:
            return {"status": "stuck", "detail": no_action}

        if not tool_calls:
            return {"status": "no_tool_calls"}

        # Record calls and check for loops
        for block in tool_calls:
            guard.record(block.name, block.input)

        loop_result = guard.is_looping()
        if loop_result:
            if injections_used >= max_injections:
                return {"status": "stuck", "detail": loop_result, "iterations": iteration}
            # Inject replanning message and reset the guard window
            messages.append({"role": "user", "content": REPLAN_INJECTION})
            guard.reset()
            injections_used += 1
            continue  # skip tool dispatch this iteration

        # Dispatch
        results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations", "iterations": max_iterations}
